import { useState, useEffect } from "react";

const BG = "data:image/jpeg;base64,";

const DETECTIONS = {
  normal: [
    { id:"D1", obj:"TANKER VEHICLE", conf:0.97, state:"PARKED — BRAKE ENGAGED", stLevel:"OK", risk:"NONE",
      x:14, y:18, w:22, h:28 },
    { id:"D2", obj:"TRANSFER HOSE", conf:0.94, state:"FULLY CONNECTED", stLevel:"OK", risk:"NONE",
      x:22, y:62, w:30, h:12 },
    { id:"D3", obj:"FLANGE JOINT", conf:0.96, state:"ALIGNED — SEALED", stLevel:"OK", risk:"NONE",
      x:46, y:50, w:14, h:16 },
    { id:"D4", obj:"VALVE C-23", conf:0.98, state:"OPEN — CORRECT POSITION", stLevel:"OK", risk:"NONE",
      x:56, y:42, w:10, h:12 },
    { id:"D5", obj:"PRESSURE GAUGE", conf:0.95, state:"1.8 MPa — WITHIN RANGE", stLevel:"OK", risk:"NONE",
      x:58, y:56, w:10, h:12 },
    { id:"D6", obj:"PIPE MANIFOLD", conf:0.92, state:"NO CORROSION / DAMAGE", stLevel:"OK", risk:"NONE",
      x:72, y:28, w:24, h:45 },
    { id:"D7", obj:"GROUND SURFACE", conf:0.91, state:"DRY — NO SPILL DETECTED", stLevel:"OK", risk:"NONE",
      x:35, y:78, w:30, h:16 },
    { id:"D8", obj:"WARNING SIGN", conf:0.99, state:"VISIBLE — COMPLIANT", stLevel:"INFO", risk:"NONE",
      x:42, y:8, w:12, h:7 },
  ],
  anomaly: [
    { id:"D1", obj:"TANKER VEHICLE", conf:0.97, state:"PARKED — BRAKE ENGAGED", stLevel:"OK", risk:"NONE",
      x:14, y:18, w:22, h:28 },
    { id:"D2", obj:"TRANSFER HOSE", conf:0.94, state:"LOOSE — COUPLING SLIPPING", stLevel:"WARN", risk:"MEDIUM",
      detail:"Cam-lock not fully engaged. Vibration may cause disconnection.",
      x:22, y:62, w:30, h:12 },
    { id:"D3", obj:"FLANGE JOINT", conf:0.89, state:"MISALIGNED — LEAK RISK", stLevel:"ALERT", risk:"HIGH",
      detail:"Bolt hole offset 8mm. Gasket compression uneven. Seal integrity compromised.",
      x:46, y:50, w:14, h:16 },
    { id:"D4", obj:"VALVE C-23", conf:0.98, state:"OPEN — SHOULD BE CLOSED", stLevel:"WARN", risk:"MEDIUM",
      detail:"Transfer paused but valve remains open. Close to prevent backflow.",
      x:56, y:42, w:10, h:12 },
    { id:"D5", obj:"PRESSURE GAUGE", conf:0.95, state:"0.4 MPa — BELOW NORMAL", stLevel:"ALERT", risk:"HIGH",
      detail:"Pressure dropped 78% in 30s. Indicates possible leak in transfer line.",
      x:58, y:56, w:10, h:12 },
    { id:"D6", obj:"PIPE MANIFOLD", conf:0.92, state:"NO CORROSION / DAMAGE", stLevel:"OK", risk:"NONE",
      x:72, y:28, w:24, h:45 },
    { id:"D7", obj:"GROUND SURFACE", conf:0.93, state:"LIQUID POOLING DETECTED", stLevel:"ALERT", risk:"CRITICAL",
      detail:"Expanding wet area (~2.1m²). Chemical spill confirmed. Evacuate zone.",
      x:35, y:78, w:30, h:16 },
    { id:"D8", obj:"WARNING SIGN", conf:0.99, state:"VISIBLE — COMPLIANT", stLevel:"INFO", risk:"NONE",
      x:42, y:8, w:12, h:7 },
  ],
};

const ST_COLORS = { OK:"#00e6a0", WARN:"#ffaa00", ALERT:"#ff3c3c", INFO:"#0099ff" };
const RISK_COLORS = { NONE:"#00e6a0", LOW:"#00e6a0", MEDIUM:"#ffaa00", HIGH:"#ff3c3c", CRITICAL:"#ff3c3c" };

function Glass({children,style}){
  return <div style={{background:"rgba(8,14,22,0.88)",backdropFilter:"blur(16px)",WebkitBackdropFilter:"blur(16px)",border:"1px solid rgba(80,200,170,0.16)",borderRadius:8,boxShadow:"0 4px 30px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.02)",...style}}>{children}</div>;
}

function DetBox({d, selected, onClick}){
  const c = ST_COLORS[d.stLevel] || "#00e6a0";
  const isAlert = d.stLevel==="ALERT";
  const isWarn = d.stLevel==="WARN";
  return (
    <div onClick={onClick} style={{
      position:"absolute", left:`${d.x}%`, top:`${d.y}%`, width:`${d.w}%`, height:`${d.h}%`,
      border:`2px solid ${c}`, borderRadius:4, cursor:"pointer",
      boxShadow: selected ? `0 0 32px ${c}55, inset 0 0 22px ${c}11` : `0 0 14px ${c}22`,
      background: isAlert ? "rgba(255,60,60,0.06)" : isWarn ? "rgba(255,170,0,0.04)" : "rgba(0,230,160,0.02)",
      transition:"all .3s ease", zIndex:20,
      animation: isAlert ? "alertBoxPulse 1.5s ease-in-out infinite" : "none",
    }}>
      {[["top","left"],["top","right"],["bottom","left"],["bottom","right"]].map(([v,hz],i)=>(
        <div key={i} style={{position:"absolute",[v]:-2,[hz]:-2,width:14,height:14,
          [`border${v[0].toUpperCase()+v.slice(1)}`]:`2.5px solid ${c}`,
          [`border${hz[0].toUpperCase()+hz.slice(1)}`]:`2.5px solid ${c}`,
          filter:`drop-shadow(0 0 3px ${c})`}}/>
      ))}
      {/* Two-line label: object + state */}
      <div style={{
        position:"absolute", top:-36, left:0, maxWidth:220,
        fontFamily:"'PingFang SC','Helvetica Neue',sans-serif",
      }}>
        <div style={{
          background:c, color: isAlert||isWarn ? "#fff" : "#081a16",
          fontSize:8, fontWeight:700, letterSpacing:1.5,
          padding:"2px 8px", borderRadius:"2px 2px 0 0", whiteSpace:"nowrap",
          boxShadow:`0 2px 8px ${c}44`,
        }}>{d.obj} — {(d.conf*100).toFixed(0)}%</div>
        <div style={{
          background:"rgba(0,0,0,0.75)", backdropFilter:"blur(8px)",
          color:c, fontSize:7.5, fontWeight:600, letterSpacing:.8,
          padding:"2px 8px", borderRadius:"0 0 2px 2px", whiteSpace:"nowrap",
          borderLeft:`1px solid ${c}33`, borderRight:`1px solid ${c}33`, borderBottom:`1px solid ${c}33`,
        }}>{isAlert?"⚠ ":isWarn?"◆ ":"✓ "}{d.state}</div>
      </div>
      {isAlert && <div style={{position:"absolute",left:0,right:0,height:2,background:`linear-gradient(90deg,transparent,${c},transparent)`,animation:"scanDetect 2s ease-in-out infinite",boxShadow:`0 0 8px ${c}`}}/>}
    </div>
  );
}

export default function DetectV3(){
  const [mode, setMode] = useState("normal");
  const [selected, setSelected] = useState(null);
  const [time, setTime] = useState("10:24:17");
  const [frameCount, setFrameCount] = useState(0);

  const dets = DETECTIONS[mode];
  const selDet = selected ? dets.find(d=>d.id===selected) : null;
  const alertC = dets.filter(d=>d.stLevel==="ALERT").length;
  const warnC = dets.filter(d=>d.stLevel==="WARN").length;
  const okC = dets.filter(d=>d.stLevel==="OK").length;

  useEffect(()=>{const iv=setInterval(()=>setTime(new Date().toTimeString().slice(0,8)),1000);return()=>clearInterval(iv)},[]);
  useEffect(()=>{const iv=setInterval(()=>setFrameCount(f=>f+1),100);return()=>clearInterval(iv)},[]);

  return(
    <div style={{width:"100%",height:"100vh",position:"relative",overflow:"hidden",fontFamily:"'PingFang SC','Helvetica Neue',Arial,sans-serif",userSelect:"none",background:"#060a10"}}>
      <style>{`
        @keyframes fI{from{opacity:0;transform:translateY(5px)}to{opacity:1;transform:translateY(0)}}
        @keyframes scanDetect{0%,100%{top:0;opacity:0}8%{opacity:1}92%{opacity:1}50%{top:calc(100% - 2px)}}
        @keyframes alertBoxPulse{0%,100%{box-shadow:0 0 15px rgba(255,60,60,0.15)}50%{box-shadow:0 0 30px rgba(255,60,60,0.35)}}
        @keyframes rB{0%,100%{opacity:1}50%{opacity:.15}}
        @keyframes aF{0%,100%{border-color:rgba(255,60,60,0.5)}50%{border-color:rgba(255,60,60,0.1)}}
      `}</style>

      <div style={{position:"absolute",inset:0,zIndex:0,backgroundImage:`url(${BG})`,backgroundSize:"cover",backgroundPosition:"center"}}/>
      <div style={{position:"absolute",inset:0,zIndex:1,background:mode==="anomaly"?"rgba(30,0,0,0.15)":"rgba(0,0,0,0.06)",transition:"background .5s"}}/>
      <div style={{position:"absolute",inset:0,zIndex:2,pointerEvents:"none",background:"repeating-linear-gradient(0deg,transparent,transparent 3px,rgba(0,0,0,0.015) 3px,rgba(0,0,0,0.015) 4px)"}}/>
      <div style={{position:"absolute",inset:0,zIndex:2,pointerEvents:"none",background:"radial-gradient(ellipse at center,transparent 55%,rgba(0,0,0,0.4) 100%)"}}/>

      {dets.map(d=>(<DetBox key={d.id} d={d} selected={selected===d.id} onClick={()=>setSelected(selected===d.id?null:d.id)}/>))}

      {/* TOP BAR */}
      <div style={{position:"absolute",top:0,left:0,right:0,height:52,background:"linear-gradient(180deg,rgba(0,0,0,.78) 0%,rgba(0,0,0,.3) 70%,transparent 100%)",display:"flex",alignItems:"center",justifyContent:"space-between",padding:"0 22px",zIndex:30}}>
        <div style={{display:"flex",alignItems:"center",gap:14}}>
          <div style={{width:7,height:7,borderRadius:"50%",background:mode==="anomaly"?"#ff3c3c":"#00e6a0",boxShadow:`0 0 8px ${mode==="anomaly"?"#ff3c3c":"#00e6a0"}`}}/>
          <span style={{fontSize:10,letterSpacing:3,color:"rgba(255,255,255,.45)",fontWeight:600}}>UAV-07 DETECTION FEED</span>
          <div style={{fontSize:8,color:"rgba(255,255,255,.25)",background:"rgba(255,255,255,.04)",padding:"2px 8px",borderRadius:2,border:"1px solid rgba(255,255,255,.06)",letterSpacing:1}}>OBJ DETECT + STATE CLS</div>
        </div>
        <div style={{fontSize:16,color:"rgba(0,230,160,.55)",letterSpacing:3}}>{time}</div>
        <div style={{display:"flex",alignItems:"center",gap:14}}>
          <span style={{fontSize:9,color:"rgba(255,255,255,.3)",letterSpacing:1}}>FRM {String(frameCount).padStart(6,"0")}</span>
          <div style={{width:5,height:5,borderRadius:"50%",background:"#ff3c3c",animation:"rB 1s ease-in-out infinite"}}/>
          <span style={{fontSize:9,color:"rgba(255,255,255,.35)",letterSpacing:1}}>REC</span>
        </div>
      </div>

      {/* RIGHT PANEL */}
      <div style={{position:"absolute",top:64,right:18,width:250,zIndex:30,animation:"fI .4s ease .1s both"}}>
        <Glass style={{padding:"16px 16px 12px"}}>
          {/* Section 1: Object Detection */}
          <div style={{fontSize:9,fontWeight:700,color:"rgba(255,255,255,.5)",letterSpacing:2.5,marginBottom:6}}>① OBJECT DETECTION</div>
          <div style={{fontSize:11,color:"#fff",marginBottom:12}}>{dets.length} targets identified</div>

          {/* Section 2: Safety Assessment */}
          <div style={{fontSize:9,fontWeight:700,color:"rgba(255,255,255,.5)",letterSpacing:2.5,marginBottom:8}}>② SAFETY ASSESSMENT</div>

          <div style={{display:"flex",gap:6,marginBottom:14}}>
            <div style={{flex:1,background:"rgba(0,230,160,.06)",borderRadius:5,padding:"7px 8px",textAlign:"center",border:"1px solid rgba(0,230,160,.12)"}}>
              <div style={{fontSize:20,fontWeight:800,color:"#00e6a0"}}>{okC}</div>
              <div style={{fontSize:7,color:"rgba(0,230,160,.5)",letterSpacing:1,marginTop:1,fontWeight:600}}>SAFE</div>
            </div>
            <div style={{flex:1,background:"rgba(255,170,0,.06)",borderRadius:5,padding:"7px 8px",textAlign:"center",border:"1px solid rgba(255,170,0,.12)"}}>
              <div style={{fontSize:20,fontWeight:800,color:"#ffaa00"}}>{warnC}</div>
              <div style={{fontSize:7,color:"rgba(255,170,0,.5)",letterSpacing:1,marginTop:1,fontWeight:600}}>WARN</div>
            </div>
            <div style={{flex:1,background:"rgba(255,60,60,.06)",borderRadius:5,padding:"7px 8px",textAlign:"center",border:"1px solid rgba(255,60,60,.12)"}}>
              <div style={{fontSize:20,fontWeight:800,color:"#ff3c3c"}}>{alertC}</div>
              <div style={{fontSize:7,color:"rgba(255,60,60,.5)",letterSpacing:1,marginTop:1,fontWeight:600}}>ALERT</div>
            </div>
          </div>

          {/* List */}
          <div style={{maxHeight:300,overflowY:"auto"}}>
            {dets.map(d=>{
              const c2=ST_COLORS[d.stLevel];
              const isSel=selected===d.id;
              return (
                <div key={d.id} onClick={()=>setSelected(isSel?null:d.id)} style={{
                  padding:"8px 10px",marginBottom:4,borderRadius:5,cursor:"pointer",
                  background:isSel?`${c2}12`:"rgba(255,255,255,.015)",
                  border:`1px solid ${isSel?`${c2}30`:"rgba(255,255,255,.03)"}`,
                  transition:"all .25s",
                }}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                    <div style={{display:"flex",alignItems:"center",gap:7}}>
                      <div style={{width:7,height:7,borderRadius:"50%",background:c2,boxShadow:`0 0 5px ${c2}`}}/>
                      <span style={{fontSize:10,fontWeight:700,color:"#fff"}}>{d.obj}</span>
                    </div>
                    <span style={{fontSize:8,color:"rgba(255,255,255,.25)"}}>{(d.conf*100).toFixed(0)}%</span>
                  </div>
                  <div style={{fontSize:9,color:c2,marginTop:3,fontWeight:d.stLevel==="ALERT"?700:500}}>
                    {d.stLevel==="ALERT"?"⚠ ":d.stLevel==="WARN"?"◆ ":"✓ "}{d.state}
                  </div>
                  {d.risk!=="NONE"&&(
                    <div style={{display:"inline-block",marginTop:4,fontSize:7,fontWeight:700,letterSpacing:1,color:RISK_COLORS[d.risk],background:`${RISK_COLORS[d.risk]}12`,padding:"1px 6px",borderRadius:2,border:`1px solid ${RISK_COLORS[d.risk]}25`}}>
                      RISK: {d.risk}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </Glass>
      </div>

      {/* LEFT: Selected detail */}
      {selDet && (
        <div style={{position:"absolute",top:64,left:18,width:230,zIndex:30,animation:"fI .3s ease"}}>
          <Glass style={{padding:"16px 16px 14px",borderColor:(ST_COLORS[selDet.stLevel])+"28"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
              <div style={{fontSize:9,fontWeight:700,color:ST_COLORS[selDet.stLevel],letterSpacing:2}}>TARGET ANALYSIS</div>
              <div onClick={()=>setSelected(null)} style={{fontSize:11,color:"rgba(255,255,255,.3)",cursor:"pointer",lineHeight:1}}>✕</div>
            </div>

            <div style={{fontSize:14,fontWeight:700,color:"#fff",marginBottom:10}}>{selDet.obj}</div>

            {/* Detection info */}
            <div style={{fontSize:8,fontWeight:600,color:"rgba(255,255,255,.35)",letterSpacing:1.5,marginBottom:6}}>① DETECTION</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6,marginBottom:12}}>
              <div style={{background:"rgba(255,255,255,.03)",borderRadius:4,padding:"7px 10px"}}>
                <div style={{fontSize:7,color:"rgba(255,255,255,.28)",letterSpacing:1,marginBottom:2}}>CONFIDENCE</div>
                <div style={{fontSize:11,color:"#fff",fontWeight:700}}>{(selDet.conf*100).toFixed(1)}%</div>
              </div>
              <div style={{background:"rgba(255,255,255,.03)",borderRadius:4,padding:"7px 10px"}}>
                <div style={{fontSize:7,color:"rgba(255,255,255,.28)",letterSpacing:1,marginBottom:2}}>POSITION</div>
                <div style={{fontSize:11,color:"rgba(255,255,255,.6)"}}>{selDet.x},{selDet.y}</div>
              </div>
            </div>

            {/* Safety assessment */}
            <div style={{fontSize:8,fontWeight:600,color:"rgba(255,255,255,.35)",letterSpacing:1.5,marginBottom:6}}>② SAFETY STATE</div>
            <div style={{background:`${ST_COLORS[selDet.stLevel]}08`,border:`1px solid ${ST_COLORS[selDet.stLevel]}20`,borderRadius:5,padding:"10px 12px",marginBottom:8}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
                <span style={{fontSize:10,fontWeight:700,color:ST_COLORS[selDet.stLevel]}}>{selDet.state}</span>
              </div>
              {selDet.risk!=="NONE"&&(
                <div style={{display:"flex",gap:8,marginTop:6}}>
                  <div style={{fontSize:7,fontWeight:700,letterSpacing:1,color:RISK_COLORS[selDet.risk],background:`${RISK_COLORS[selDet.risk]}15`,padding:"2px 8px",borderRadius:2}}>
                    RISK: {selDet.risk}
                  </div>
                </div>
              )}
            </div>

            {/* Detail explanation for anomalies */}
            {selDet.detail&&(
              <div style={{background:"rgba(255,60,60,.06)",border:"1px solid rgba(255,60,60,.15)",borderRadius:5,padding:"10px 12px"}}>
                <div style={{fontSize:8,color:"#ff3c3c",letterSpacing:1.5,fontWeight:700,marginBottom:5}}>③ DIAGNOSIS</div>
                <div style={{fontSize:9.5,color:"rgba(255,255,255,.55)",lineHeight:1.6}}>{selDet.detail}</div>
                <div style={{marginTop:8,fontSize:8,color:"rgba(255,255,255,.3)",letterSpacing:1}}>→ Auto-reported to Control Center</div>
              </div>
            )}
          </Glass>
        </div>
      )}

      {/* BOTTOM BAR */}
      <div style={{position:"absolute",bottom:0,left:0,right:0,background:"linear-gradient(0deg,rgba(0,0,0,.82) 0%,rgba(0,0,0,.35) 65%,transparent 100%)",padding:"18px 22px 14px",zIndex:30,display:"flex",alignItems:"flex-end",justifyContent:"space-between"}}>
        <div style={{display:"flex",gap:28}}>
          {[
            {k:"PIPELINE",v:"① Detect → ② Classify → ③ Assess"},
            {k:"ALTITUDE",v:"25m AGL"},
            {k:"OBJECTS",v:`${dets.length} DETECTED`},
            {k:"LATENCY",v:"42ms"},
          ].map((item,i)=>(
            <div key={i} style={{animation:`fI .4s ease ${i*.08}s both`}}>
              <div style={{fontSize:7,letterSpacing:2,color:"rgba(255,255,255,.18)",marginBottom:2,fontWeight:600}}>{item.k}</div>
              <div style={{fontSize:11,color:"rgba(255,255,255,.55)"}}>{item.v}</div>
            </div>
          ))}
        </div>
        <div style={{display:"flex",gap:10}}>
          <button onClick={()=>{setMode("normal");setSelected(null)}} style={{
            padding:"9px 20px",borderRadius:6,fontSize:10,fontWeight:700,letterSpacing:2,cursor:"pointer",
            transition:"all .3s",
            background:mode==="normal"?"rgba(0,230,160,.15)":"rgba(255,255,255,.03)",
            border:`1px solid ${mode==="normal"?"rgba(0,230,160,.3)":"rgba(255,255,255,.06)"}`,
            color:mode==="normal"?"#00e6a0":"rgba(255,255,255,.3)",
            fontFamily:"'PingFang SC','Helvetica Neue',sans-serif",
          }}>✓ NORMAL</button>
          <button onClick={()=>{setMode("anomaly");setSelected(null)}} style={{
            padding:"9px 20px",borderRadius:6,fontSize:10,fontWeight:700,letterSpacing:2,cursor:"pointer",
            transition:"all .3s",
            background:mode==="anomaly"?"rgba(255,60,60,.15)":"rgba(255,255,255,.03)",
            border:`1px solid ${mode==="anomaly"?"rgba(255,60,60,.3)":"rgba(255,255,255,.06)"}`,
            color:mode==="anomaly"?"#ff3c3c":"rgba(255,255,255,.3)",
            fontFamily:"'PingFang SC','Helvetica Neue',sans-serif",
          }}>⚠ ANOMALY</button>
        </div>
      </div>

      {mode==="anomaly"&&alertC>0&&<div style={{position:"absolute",inset:5,zIndex:50,pointerEvents:"none",border:"2px solid #ff3c3c",borderRadius:8,animation:"aF .8s ease-in-out infinite"}}/>}
    </div>
  );
}
